import{_ as t,o as i,c as a,ag as s}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt2802.jpg",u="/images/lekt2801.jpg",l="/images/lekt2804.jpg",r="/images/lekt2803.jpg",o="/images/lekt2805.jpg",g=JSON.parse('{"title":"Lektion 28","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion28.md","filePath":"lektionen/lektion28.md"}'),d={name:"lektionen/lektion28.md"};function p(m,e,h,b,c,k){return i(),a("div",null,[...e[0]||(e[0]=[s('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-28" tabindex="-1">Lektion 28 <a class="header-anchor" href="#lektion-28" aria-label="Permalink to &quot;Lektion 28&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>28.1. Das Kausativum (णि, णिच्, कारित)</li><li>28.2. Satzkonstruktion mit dem Kausativ (णि, णिच्, कारित)</li><li>28.3. Bildung des Präsensstamms zum Kausativ (णि, णिच्, कारित)</li><li>28.4. Bildung des Passivs (यक्)  zum Kausativ</li><li>28.5. Bildung des Futurs (ऌत्, भविष्यन्ती f.) zum Kausativ</li><li>28.6. Bildung des PPP (क्त) zum Kausativ</li><li>28.7. Bildung des Absolutivs (क्त्वा । ल्यप्) zum Kausativ</li><li>28.8. Bildung des Infinitivs (तुमुन्) zum Kausativ</li><li>28.9. Die 10. Präsensklasse (चुरादि = चुर् u.s.w.)</li><li>28.10. Wortliste</li><li>28.11. Übung</li></ul><h2 id="_28-1-das-kausativum-णि-णिच्-कारित" tabindex="-1">28.1. Das Kausativum (णि, णिच्, कारित) <a class="header-anchor" href="#_28-1-das-kausativum-णि-णिच्-कारित" aria-label="Permalink to &quot;28.1. Das Kausativum (णि, णिच्, कारित)&quot;">​</a></h2><p>Will man ausdrücken, dass jemand oder etwas veranlasst oder bewirkt, dass jemand anderer oder etwas anderes etwas tut oder erleidet, was durch eine Wurzel (mit oder ohne Präverb) ausgedrückt wird, so verwendet man das Kausativum (णि, णिच्, कारित).</p><p>Beispiel:</p><blockquote><p>गम् &quot;gehen&quot; » Kausativ: गमयति &quot;er veranlasst, dass jemand geht; er schickt&quot;</p><p>दृश् &quot;sehen&quot; » Kausativ: दर्शयति &quot;er macht sehen = er zeigt&quot;</p></blockquote><h2 id="_28-2-satzkonstruktion-mit-dem-kausativ-णि-णिच्-कारित" tabindex="-1">28.2. Satzkonstruktion mit dem Kausativ (णि, णिच्, कारित) <a class="header-anchor" href="#_28-2-satzkonstruktion-mit-dem-kausativ-णि-णिच्-कारित" aria-label="Permalink to &quot;28.2. Satzkonstruktion mit dem Kausativ (णि, णिच्, कारित)&quot;">​</a></h2><p>Schema 1:</p><p>Wenn die dem Kausativ zugrundeliegende Wurzel (mit oder ohne Präverb) INTRANSITIV ist (d.h. kein Akkusativobjekt bei sich haben kann) oder Bewegung, Wissen, Information oder Essen ausdrückt:</p><blockquote><p>Agens (कर्तृ) des Kausativums im Nominativ (प्रथमा) -- Agens der veranlassten Handlung im Akkusativ (द्वितीया) -- (Ziel der Bewegung, Objekt des Wissens usw. im Akkusativ = द्वितीया) -- Verb im Kausativ</p></blockquote><p>Beispiele:</p><blockquote><p>दुर्जनो रामं मोहयति = &quot;ein böser Mensch bewirkt, dass Rāma verwirrt ist = verwirrt den Rāma = bewirkt, dass Rāma irrt&quot;</p><blockquote><p>Ergebnis: रामो मुह्यति = &quot;Rāma ist verwirrt / verblendet / irrt.&quot;</p></blockquote><p>रामः शत्रून्स्वर्गं गमयति = &quot;Rāma macht die Feinde in den Himmel gehen = schickt die Feinde in den Himmel&quot;</p><blockquote><p>Ergebnis: शत्रवः स्वर्गं गच्छन्ति = &quot;die Feinde gehen zum Himmel / kommen in den Himmel&quot;</p></blockquote><p>गुरू रामं वेदार्थं वेदयति = &quot;Der Meister macht Rāma den Sinn des Veda wissen = erklärt / lehrt Rāma den Sinn des Veda&quot;</p><blockquote><p>Ergebnis: रामो वेदार्थं वेत्ति = &quot;Rāma kennt / versteht den Sinn des Veda&quot;</p></blockquote><p>स रामं वेदमध्यापयति = &quot;er lehrt Rāma den Veda&quot;</p><blockquote><p>Ergebnis: रामो वेदमधीते &quot;Rāma studiert den Veda&quot;</p></blockquote><p>रामो देवानमृतमाशयति = &quot;Rāma lässt die Götter Unsterblichkeitsspeise essen = gibt den Göttern Unsterblichkeitsspeise zu essen&quot; (अश् 9 &quot;essen&quot;)</p><blockquote><p>Ergebnis: देवा अमृतमश्नन्ति &quot;Die Götter essen Unsterblichkeitsspeise&quot;</p><p><img src="'+n+'" alt=""><br> Abb.: स नरान्प्रबन्धविज्ञानमध्यापयति (प्रबन्ध = Management)<br> Jadavpur University = যাদবপুর বিশ্ববিদ্যালয়,  Kolkatta = কলকাতা <br> [Bildquelle: noii&#39;s. -- <a href="http://www.flickr.com/photos/noii/2423810775/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/noii/2423810775/</a>. -- Zugriff am 2008-12-19. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p></blockquote></blockquote><p>Nach Schema 1 konstruiert u.a. auch die Wurzel दृश्:</p><blockquote><p>(स) रामं पुत्रं दर्शयति = &quot;er zeigt dem Rāma den Sohn&quot;</p></blockquote><p>Ausnahmen zu Schema 1 siehe unter Schema 2</p><p>Der folgende Vers fasst Beispiele für die Kausativbildung nach Schema 1 zusammen (bei den Verbalformen handelt es sich jeweils um die 3. Person Imperfekt Parasmaipada):</p><blockquote><p>शत्रूनगमयत्स्वर्गं<br> वेदार्थं स्वानवेदयत् ।<br> आशयच्चामृतं देवान्<br> वेदमध्यापयद्विधिम् ।<br> आसयत्सलिले पृथ्वीं<br> यः स मे श्रीहरिगतिः ॥</p><p>Meine Zuflucht und mein Ziel ist Hari,<br> Der die Feinde in den Himmel schickte,<br> Der die Seinen die Bedeutung des Veda lehrte,<br> Der der die Götter mit Unsterblichkeitsspeise speiste,<br> Der den Schöpfer den Veda lehrte,<br> Der die Erde in das Wasser setzte.</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: स मे श्रीहरिगतिः<br> ISKCON (International Society for Krishna Consciousness) -Tempel, Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: Ramki&#39;s reflections. -- <a href="http://www.flickr.com/photos/ramakrishnan/407023039/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ramakrishnan/407023039/</a>. -- Zugriff am 2008-12-19. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Schema 2:</p><p>Bei transitiven Verben (außer den unter Schema 1 genannten). Ebenfalls bei allen Verben, wenn das durch das Kausativ Bezeichnete veranlasst wird (wenn das Kausativ also ein Kausativ zum Kausativ ist):</p><blockquote><blockquote><p>Agens (कर्तृ) des Kausativums im Nominativ (प्रथमा) -- Agens der veranlassten Handlung im Instrumentalis (तृतीया) -- Objekt der veranlassten Handlung in dem Kasus, den es nach dem einfachen Verb hätte (d.h. meist im Akkusativ) -- Verb im Kausativum</p></blockquote></blockquote><p>Beispiele:</p><blockquote><p>(स) रामेण भार्यां त्याजयति = &quot;Er veranlasst den Rāma, seine Frau zu verlassen&quot;</p><blockquote><p>Ergebnis: रामो भार्यां त्यजति = &quot;Rāma verlässt seine Frau&quot;</p></blockquote><p>विष्णुमित्रो रामेण गोविन्दं गमयति = &quot;Viṣṇumitra veranlasst den Rāma, dass dieser den Govinda veranlasst zu gehen = Viṣṇumitra lässt Rāma den Govinda fortschicken&quot;</p><blockquote><p>Ergebnis: रामो गोविन्दम् गमयति = &quot;Rāma schickt den Govinda fort&quot;</p><blockquote><p>Ergebnis dieses Ergebnisses: गोविन्दो गच्छति = &quot;Govinda geht&quot;</p></blockquote></blockquote></blockquote><p>Ausnahmen zu Schema 1:</p><p>Nach Schema 2 konstruieren u.a. auch folgende Verben:</p><p>Kausativ zu</p><ul><li>नी &quot;führen&quot;</li><li>वह् &quot;fahren&quot; (nur wenn der Agens der veranlassten Handlung kein Fahrer ist&quot;</li><li>स्मृ &quot;vergegenwärtigen&quot; (es gibt dazu Ausnahmen)</li><li>अद् &quot;essen&quot;</li><li>खाद् &quot;kauen&quot;</li></ul><p>Beispiele:</p><blockquote><p>रामो भृत्येन भारं नाययति वाहयति वा = &quot;Rāma lässt den Diener die Last führen bzw. fahren&quot;</p><blockquote><p>Ergebnis:  भृत्यो भारं नयति वहति वा = &quot;Der Diener führt bzw. fahrt die Last&quot;</p></blockquote><p>रामो बालेनान्नमादयति खादयति वा = &quot;Rāma lässt den Knaben Speise essen bzw. kauen&quot;</p><blockquote><p>Ergebnis: बालो ऽन्नमत्ति खादति वा = &quot;der Knabe isst oder kaut Speise&quot;</p></blockquote><p>(स) रामेण स्मारयति = &quot;Er bewirkt, dass Rāma sich erinnert&quot;</p><blockquote><p>Ergebnis: रामः स्मरति = Rāma erinnert sich&quot;</p></blockquote></blockquote><p>Folgende Kausative können sowohl nach Schema 1 als auch nach Schmea 2 konstruieren:</p><ul><li>ह्र् &quot;halten, holen&quot;</li><li>कृ &quot;tun, machen&quot;</li><li>Ātmanepadakausativ zu दृश्</li></ul><p>Beispiele:</p><blockquote><p>रामो भृत्यं कटं कारयति हारयति वा = &quot;Rāma lässt den Diener eine Matte (कट m.) machen bzw. holen&quot;</p><p>oder:</p><p>रामो भृत्येन कटं कारयति हारयति वा</p><blockquote><p>Ergebnis: भृत्यः कटं करोति हरति वा = &quot;Der Diener macht bzw. holt eine Matte&quot;</p></blockquote><p>रामो बालं प्रतिमां दर्शयते = &quot;Rāma lässt den Knaben das Bildnis sehen = zeigt dem Knaben das Bildnis (im eigenen Interesse)&quot;</p><p>oder:</p><p>रामो बालेन प्रतिमां दर्शयते</p><blockquote><p>Ergebnis: बालः प्रतिमां पश्यति = &quot;der Knabe sieht das Bildnis&quot;</p></blockquote></blockquote><p>Wird das Kausativum in einer Passivkonstruktion verwendet, so findet fast immer folgendes Schema Anwendung:</p><p>Schema A (Passivkonstruktion):</p><blockquote><p>Agens des Kausativums im Instrumentalis (तृतीया) -- Agens der veranlassten Handlung im Nominativ (प्रथमा) -- Objekt der veranlassten Handlung in dem Kasus, den es nach dem einfachen Verb hätte (d.h. meist im Akkusativ) -- Verb im Kausativum</p></blockquote><p>Beispiele:</p><blockquote><p>गुरुणा रामो ग्रामं गम्यते = &quot;Der Meister schickt Rāma ins Dorf&quot;</p><blockquote><p>Ergebnis: रामो ग्रामं गच्छति = &quot;Rāma geht ins Dorf&quot;</p></blockquote><p>रामेण भृत्यः कतं कार्यते = &quot;Rāma lässt den Diener eine Matte machen&quot;</p><blockquote><p>Ergebnis: भृत्यः कटं करोति = &quot;Der Diener macht eine Matte&quot;</p></blockquote><p>रामेण भृत्यो भारं हार्यते = &quot;Rāma lässt den Diener die Last holen&quot;</p><blockquote><p>Ergebnis: भृत्यो भारं हरति = &quot;Der Diener holt die Last&quot;</p></blockquote></blockquote><h2 id="_28-3-bildung-des-prasensstamms-zum-kausativ-णि-णिच्-कारित" tabindex="-1">28.3. Bildung des Präsensstamms zum Kausativ (णि, णिच्, कारित) <a class="header-anchor" href="#_28-3-bildung-des-prasensstamms-zum-kausativ-णि-णिच्-कारित" aria-label="Permalink to &quot;28.3. Bildung des Präsensstamms zum Kausativ (णि, णिच्, कारित)&quot;">​</a></h2><p>An den Kausativstamm treten die thematischen Endungen des Präsensstamms</p><p>Es gibt verschiedene Bildungstypen:</p><p>Bildungstyp 1:</p><p>(meist) hochstufige Wurzel + -aya-</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Kausativ 3. sg. Indikativ Präsens</th><th>Bedeutung</th></tr></thead><tbody><tr><td>विश्</td><td>वेशयति (veś-aya-ti)</td><td>er/sie/es lässt eintreten, führt hinein</td></tr><tr><td>लुभ्</td><td>लोभयति</td><td>begehren machen, begehrlich machen, verlocken</td></tr><tr><td>दृश्</td><td>दर्शयति</td><td>sehen machen = zeigen</td></tr><tr><td>वृत्</td><td>वर्तयति</td><td>sich drehen machen, wenden (transitiv), rollen (transitiv), ins Rollen bringen</td></tr></tbody></table></blockquote><p>Bildungstyp 2:</p><p>dehnstufige Wurzel + -aya-</p><p>Oft bei Wurzeln, die vokalisch enden, und bei Wurzeln, bei denen auf -a- ein einziger Endkonsonant folgt.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Kausativ 3. sg. Indikativ Präsens</th><th>Bedeutung</th></tr></thead><tbody><tr><td>भू</td><td>भावयति (aus: bhau-aya-ti)</td><td>bewirken, dass jemand oder etwas wird, hervorbringen</td></tr><tr><td>इ</td><td>आययति (aus: ai-aya-ti)</td><td>bewirken, dass jemand geht</td></tr><tr><td>नी</td><td>नाययति (aus: nai-aya-ti)</td><td>führen lassen</td></tr><tr><td>कृ</td><td>कारयति  (kār-aya-ti)</td><td>machen lassen</td></tr><tr><td>वच्</td><td>वाचयति (vāc-aya-ti)</td><td>sprechen lassen, sprechen machen, (einen Text sprechen machen =) laut lesen</td></tr></tbody></table></blockquote><p>Bildungstyp 3:</p><p>tiefstufige Wurzel + -aya-</p><p>Kommt vor.</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Kausativ 3. sg. Indikativ Präsens</th><th>Bedeutung</th></tr></thead><tbody><tr><td>दुष्</td><td>दूषयति  (dūṣ-aya-ti)</td><td>(jemanden)) verderben</td></tr></tbody></table></blockquote><p>Bildungstyp 4:</p><p>Wurzel + -paya-</p><p>Bei Wurzeln auf -ā und einigen anderen Wurzeln.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Kausativ 3. sg. Indikativ Präsens</th><th>Bedeutung</th></tr></thead><tbody><tr><td>स्था</td><td>स्थापयति  (sthā-paya-ti)</td><td>stehen machen, aufstellen</td></tr><tr><td>इ + अधि 2Ā</td><td></td><td></td></tr><tr><td>&quot;studieren&quot;</td><td>अध्यापयति (aus: adhi+ā-paya-ti)</td><td></td></tr><tr><td>(zur Erklärung siehe Thumb-Hauschildt Bd. I,2 S. 341)</td><td>studieren lassen, unterrichten</td><td></td></tr></tbody></table></blockquote><p>Unregelmäßige Bildungen:</p><p>Einheimischen Grammatiker betrachten folgende Formen als Kausativa:</p><ul><li>हन्  : Kaus. घातयति  1  &quot;erschlagen lassen, töten lassen&quot;</li><li>पा 2 &quot;hüten&quot;: पालयति 2 &quot;hinüberbringen, retten, schützen&quot;</li></ul><p>Anmerkungen:</p><p>1 घातयति  ist in Wirklichkeit ein Verb, das vom Substantiv घात m. &quot;Schlag&quot; abgeleitet ist (denominativum) und anstelle des Kausativums von हन् verwendet wird.</p><p>2 पालयति ist ein echtes Kausativum, allerdings zur Wurzel पृ 3 &quot;hinüberbringen, retten, schützen&quot;: पारयति (pār-aya-ti) » पालयति (in einigen Gegenden Indiens entspricht dem r ein l, in anderen umgekehrt dem l ein r).</p><h2 id="_28-4-bildung-des-passivs-यक्-zum-kausativ" tabindex="-1">28.4. Bildung des Passivs (यक्)  zum Kausativ <a class="header-anchor" href="#_28-4-bildung-des-passivs-यक्-zum-kausativ" aria-label="Permalink to &quot;28.4. Bildung des Passivs (यक्)  zum Kausativ&quot;">​</a></h2><p>Das Passiv zum Kausativ wird so gebildet:</p><p>Kausativstamm ohne -aya- + Passivsuffix -ya-</p><p>Beispiele:</p><blockquote><p>भाव्यते (bhāv-ya-te) &quot;er/sie/es wird hervorgebracht&quot;</p><p>स्थाप्यते (sthāp-ya-te) &quot;er/sie/es wird aufgestellt&quot;</p></blockquote><p>Während das Passiv zur ursprünglichen Wurzel meist von der tiefstufigen Wurzel gebildet wird, kann man das Passiv des Kausativums meist daran erkennen, dass es von der hoch- bzw. dehnstufigen Wurzel gebildet wird.</p><h2 id="_28-5-bildung-des-futurs-ऌत्-भविष्यन्ती-f-zum-kausativ" tabindex="-1">28.5. Bildung des Futurs (ऌत्, भविष्यन्ती f.) zum Kausativ <a class="header-anchor" href="#_28-5-bildung-des-futurs-ऌत्-भविष्यन्ती-f-zum-kausativ" aria-label="Permalink to &quot;28.5. Bildung des Futurs (ऌत्, भविष्यन्ती f.) zum Kausativ&quot;">​</a></h2><p>Das Futur des Kausativs wird vom Kausativstamm gebildet, dabei fällt das auslautende -a- des Kausativsuffixes aus:</p><p>-ay-iṣya-</p><p>Beispiel:</p><blockquote><p>बुध् Futur-Kausativ: बोधयिष्यति (bodh-ay-i-ṣya-ti): &quot;er/sie/es wird aufwecken&quot;</p></blockquote><h2 id="_28-6-bildung-des-ppp-क्त-zum-kausativ" tabindex="-1">28.6. Bildung des PPP (क्त) zum Kausativ <a class="header-anchor" href="#_28-6-bildung-des-ppp-क्त-zum-kausativ" aria-label="Permalink to &quot;28.6. Bildung des PPP (क्त) zum Kausativ&quot;">​</a></h2><p>Kausativstamm auf -ay- (ohne auslautendes a) + -i- + -ta</p><p>Beispiele:</p><blockquote><p>गम्  गमयति  गमित (gam-i-ta)  &quot;gesendet&quot; (PPP der einfachen Wurzel: गत)</p><p>स्था  स्थापयतै  स्थापित (sthāp-i-ta) &quot;aufgestellt&quot;</p></blockquote><h2 id="_28-7-bildung-des-absolutivs-क्त्वा-।-ल्यप्-zum-kausativ" tabindex="-1">28.7. Bildung des Absolutivs (क्त्वा । ल्यप्) zum Kausativ <a class="header-anchor" href="#_28-7-bildung-des-absolutivs-क्त्वा-।-ल्यप्-zum-kausativ" aria-label="Permalink to &quot;28.7. Bildung des Absolutivs (क्त्वा । ल्यप्) zum Kausativ&quot;">​</a></h2><p>Das Absolutivum auf -tvā wird vom Kausativstamm auf -ay- (ohne auslautendes a) gebildet:</p><p>Kausativstamm auf -ay- + -i- + -tvā</p><p>Beispiel:</p><blockquote><p>स्थापयित्वा (sthā-pay-i-tvā) &quot;nachdem er aufgestellt hat&quot;</p></blockquote><p>Das Absolutivum auf -ya tritt bei Kausativa mit Präverb in der Regel an Kausativstamm ohne -aya-</p><p>Beispiele:</p><blockquote><p>प्रबुध्  प्रबोधयति  प्रबोध्य  (pra-bodh-ya) &quot;nachdem er aufgeweckt hat&quot;</p><p>आनी  आनयति  आनय्य  (ā-nāy-ya) &quot;nachdem er heranführen gelassen hat, nachdem er bringen gelassen hat&quot;</p></blockquote><p>Enthält jedoch die Wurzelsilbe des Kausativs ein kurzes -a- vor einem einzigen Konsonanten, tritt das -ya des Absolutivums an den Kausativstamm auf -ay- (ohne auslautendes a)</p><p>Beispiel:</p><blockquote><p>आगम्  आगमयति  आगमय्य  (ā-gamay-ya) &quot;nachdem er kommen gelassen hat&quot;</p></blockquote><h2 id="_28-8-bildung-des-infinitivs-तुमुन्-zum-kausativ" tabindex="-1">28.8. Bildung des Infinitivs (तुमुन्) zum Kausativ <a class="header-anchor" href="#_28-8-bildung-des-infinitivs-तुमुन्-zum-kausativ" aria-label="Permalink to &quot;28.8. Bildung des Infinitivs (तुमुन्) zum Kausativ&quot;">​</a></h2><p>Der Infinitiv zum Kausativ wird vom Kausativstamm auf -ay- (ohne auslautendes a) gebildet:</p><p>Kausativstamm auf -ay-  + -i- + -tum</p><p>Beispiel:</p><blockquote><p>जन्  जनयति  जनयितुम् (janay-i-tum) &quot;um zu erzeugen&quot;</p></blockquote><h2 id="_28-9-die-10-prasensklasse-चुरादि-चुर्-u-s-w" tabindex="-1">28.9. Die 10. Präsensklasse (चुरादि = चुर् u.s.w.) <a class="header-anchor" href="#_28-9-die-10-prasensklasse-चुरादि-चुर्-u-s-w" aria-label="Permalink to &quot;28.9. Die 10. Präsensklasse (चुरादि = चुर् u.s.w.)&quot;">​</a></h2><p>In gleicher Weise wie die Kausativa bilden das Präsens (und die anderen tempora) einige Wurzeln der 10. Präsensklasse, ohne Kausativa zu sein.</p><p>Beispiele:</p><ol><li>Dehnstufige Wurzel + -aya- : कम् 10Ā  कामयते &quot;lieben&quot;</li><li>Hochstufige Wurzel + -aya- : चुर् 10U  चोरयति  &quot;stehlen&quot; ; Futur:  चोर्यिष्यते ; Pass.:  चोर्यते</li></ol><p>Die Formen des Kausativs zu Verben der 10. Präsensklasse sind identisch mit den Formen des einfachen Verbs. Die Entscheidung darüber, ob ein kausativ vorliegt, ist nur aus dem Sinn bzw. manchmal aus der Konstruktion möglich.</p><h2 id="_28-10-wortliste" tabindex="-1">28.10. Wortliste <a class="header-anchor" href="#_28-10-wortliste" aria-label="Permalink to &quot;28.10. Wortliste&quot;">​</a></h2><p>विद् 2P वेत्ति , विदन्ति : wissen, kennen</p><blockquote><p>Fut. वेदिष्यति <br> Pass. विद्यते <br> Kaus. वेदयति <br> PPP विदित <br> Inf. वेदितुम्</p><p>davon:</p><p>विद्या f.,  वेद m.</p></blockquote><p>विद् 6U विन्दति (!):  finden</p><blockquote><p>Fut. वेदिष्यति / वेत्स्यत् <br> Pass. विद्यते : es gibt, es ist vorhanden <br> Kaus. वेदयति <br> PPP विन्न /  वित्त <br> Inf. वेदितुम्  वेत्तुम्</p></blockquote><p>इ + अधि 2Ā  अधीते , अधीयते : studieren, auswendig lernen</p><blockquote><p>Kaus. अध्यापयति : studieren lassen, unterrichten</p><p>davon:</p><p>अध्ययन n.:  Studium (bes. des Veda)</p><p>अध्याय m.: Lektion, Kapitel (Abschnitt zum Auswendiglernen)</p></blockquote><p>कम् 10Ā  कामयते : lieben</p><blockquote><p>Fut. कामयिष्यते /  कमिष्यते <br> Pass. काम्यते <br> Kaus. कामयति <br> PPP  कान्त (!)<br> Inf. कामयितुम् / कमितुम्</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: कृष्णो  राधां  कामयति<br> Gemälde von राजा रवि वर्मा (1848 - 1906)<br> [Bildquelle: Wikipedia. Public domain]</p><p>चुर् 10 चोरयति : stehlen</p><blockquote><p>Fut. चोरयिष्यति <br> Pass. चोर्यते <br> Kaus. चोरयति <br> PPP चोरित <br> Inf. चोरितुम्</p></blockquote><p>Merken Sie sich besonders die Bedeutung der kausativa zu folgenden Verben:</p><blockquote><p>दृश्  दर्शयति : zeigen</p><p>मन्  मानयति : hochschätzen, ehren (ist vermutlich aber ein Denominativ zu मान &quot;Ehre&quot;)</p><p>वच्  वाचयति : auch: laut lesen (einen Text sprechen machen)</p><p>वद्  वादयति : auch: ein Musikinstrument zum Sprechen bringen = ein Musikinstrument spielen</p></blockquote><p><img src="'+r+'" alt=""><br> Abb.: वीणां  वादयति<br> [Bildquelle: Kelvin Kay / Wikipedia. GNU FDLicense]</p><p>भार m.: Last</p><p><img src="'+o+'" alt=""><br> Abb.: बाला भारं हरति<br> Bei Ahmedabad<br> [Bildquelle: m-bot. -- <a href="http://www.flickr.com/photos/72494286@N00/2127838811/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/72494286@N00/2127838811/</a>. -- Zugriff am 2008-12-20. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p><p>भृत्य m.: Untergebener, Diener</p><h2 id="_28-11-ubung" tabindex="-1">28.11. Übung <a class="header-anchor" href="#_28-11-ubung" aria-label="Permalink to &quot;28.11. Übung&quot;">​</a></h2><p>A) Bilden Sie das Kausativum zu folgenden Verbformen und Partizipialformen und geben Sie die Bedeutung an:</p><p>1. Mit hochstufiger Wurzel:</p><ol><li>अर्हन्ति</li><li>प्राप्य</li><li>एषिष्यन्ति</li><li>कुप्यति</li><li>कर्क्ष्यति</li><li>क्रुध्यन्ती</li><li>चोर्यते</li><li>गन्तुम्</li><li>जातः</li><li>देक्ष्यन्ति</li><li>दोग्धि</li><li>माद्यन्</li><li>द्रक्ष्यति</li><li>द्वेष्टि</li><li>नर्तितुम्</li><li>भोत्स्यन्ते</li><li>मुञ्चन्ति</li><li>पृच्छन्ति</li><li>मुह्यति</li><li>योत्स्यन्</li><li>रक्ष्यते</li><li>रोदिति</li><li>लुब्धा</li><li>प्रविश्य</li><li>वर्तते</li><li>सिक्त्वा</li><li>स्रक्ष्यति</li><li>लिम्पन्ति</li><li>वृद्धाः</li></ol><p>2. Mit dehnstufiger Wurzel:</p><ol><li>अत्ति</li><li>अस्यन्ति</li><li>एष्यति</li><li>संस्कृतम्</li><li>चरति</li><li>तनोति</li><li>खाद्यते</li><li>धक्ष्यति</li><li>उपानेष्यति</li><li>पच्यते</li><li>पतन्ति</li><li>पत्स्यते</li><li>भक्तः</li><li>भवति</li><li>मंस्यन्ते</li><li>म्रियते</li><li>इज्यते</li><li>वक्ति</li><li>प्रोद्य</li><li>शृणोति</li><li>सुन्वन्ति</li><li>स्तौति</li><li>विस्मृत्य</li><li>उषितः</li><li>वसिता</li><li>अश्नुते</li><li>आसते</li><li>त्यक्ष्यता</li><li>धृतेन</li><li>म्रियन्ते</li><li>यजतः</li><li>उक्ते</li><li>उद्यन्ते</li><li>शक्नुवन्ति</li><li>श्रोष्यन्तः</li><li>सीदति</li><li>सोढायाः</li><li>हरन्ती</li><li>ऊढया</li></ol><p>3. Kausativ auf -पय</p><ol><li>स्थित्वा</li></ol><p>4. Beachten und lernen Sie besonders folgende Kausativbildungen</p><ol><li>दुष् दूषयति</li><li>पा 1 (&quot;trinken2) पाययति (aus: pai-aya-ti)</li><li>पा 2 (&quot;schützen&quot;) पालयति</li><li>लभ् लम्भयति</li><li>हन् घातयति</li><li>जि जापयति</li><li>जीव् जीवयति</li></ol><p>B. Übersetzen Sie folgende Sätze, lösen Sie die Komposita in Sanskrit auf und bilden Sie mittels der einfachen Verben Sätze, die ausdrücken, was geschieht, wenn das durch das Kausativum ausgedrückte bewirkt wird:</p><p>Beispiel: रामो दासं भारं हारयति » दासो भारं हरति</p><p>शत्रुजयाय क्षत्रियो ब्राह्मणेन हरिहरं याजयित्वारीन्योत्स्यते ॥१॥</p><p>गुरुर्बालान्वेदमध्याप्य गृहं गतः ॥२॥</p><p>गर्भगृहे देवीप्रतिमा दर्श्यते ॥३॥</p><p>यजन्नग्निनान्नमादयति पानं च पाययति ॥४॥</p><p>पुत्रे जाते ब्राह्मणी दासं ब्राह्मनं गमयति । ब्राह्मणस्तं दासं गृहं प्रवेश्य पुत्रं पृच्छति । सुभगः पुत्र इति दासो वक्ति । तच्छ्रुत्वा ब्राह्मणो सुखतां गच्छति ॥५॥</p><p>स्तुवता नरेण देवा महाकवेः स्तोत्राणि श्राविताः ॥६॥</p><p>आर्ययोधैर्महायुद्धे ऽरयो मार्यन्ते ॥७॥</p><p>सत्क्षत्रिया ब्राह्मणेनेष्टदेवतापूजां कारयति । स ब्राह्मणः पूजां कृत्वा क्षत्रियाया धनमेषिष्यति ॥८॥</p><p>धनं जेतुं महाक्षत्रियो योधव्याघ्रैर्व्रतानि चारयिष्यति ॥९॥</p><p>पापाद्मोक्षार्थेन सुगत आर्यजनानार्यसत्यानि बोधयति ॥१०॥</p>',144)])])}const v=t(d,[["render",p]]);export{g as __pageData,v as default};
